import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Random Image API او Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Other/random-image-api-and-public-gallery.md","filePath":"ps/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"ps/Other/random-image-api-and-public-gallery.md"};function o(s,t,l,c,n,p){return a(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="random-image-api-او-public-gallery" tabindex="-1">Random Image API او Public Gallery <a class="header-anchor" href="#random-image-api-او-public-gallery" aria-label="Permalink to &quot;Random Image API او Public Gallery&quot;">​</a></h1><p>دواړه features دلته تنظیمېږي:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API له ټاکلو directories څخه یو random file راګرځوي. دا د site backgrounds، avatar rotation یا له external pages څخه random image calls لپاره ګټور دی.</p><p>له فعالېدو وروسته، دا وکاروئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-settings" tabindex="-1">Random Image API Settings <a class="header-anchor" href="#random-image-api-settings" aria-label="Permalink to &quot;Random Image API Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>موخه</th></tr></thead><tbody><tr><td>Enable</td><td>د <code>/random</code> endpoint on یا off کوي. کله چې disabled وي، access منع وي.</td></tr><tr><td>Directories</td><td>محدودوي چې random API کوم directories کارولای شي. هغه directories چې دلته شامل نه وي، API یې نه شي کارولای.</td></tr><tr><td>Call demo</td><td>random API links جوړوي چې مستقیم یې copy کولای شئ.</td></tr></tbody></table><p>څو directories ټاکلای شئ. د بېلګې په توګه، که یوازې <code>/landscape/</code> او <code>/portrait/</code> allowed وي، random API یوازې له هغو directories او subdirectories څخه files ټاکلای شي.</p><h2 id="random-image-api-parameters" tabindex="-1">Random Image API Parameters <a class="header-anchor" href="#random-image-api-parameters" aria-label="Permalink to &quot;Random Image API Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Example</th><th>موخه</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>random directory ټاکي.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>media type ټاکي. <code>image</code>، <code>video</code>، <code>audio</code> یا comma-separated combinations وکاروئ.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>image orientation filter کوي. <code>portrait</code>، <code>landscape</code> یا <code>auto</code> وکاروئ.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>return format. تش وي redirect کوي، <code>url</code> plain text URL ورکوي، <code>json</code> JSON ورکوي.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>له <code>type=url</code> سره د full URL ورکولو لپاره کارېږي.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>د age rating له مخې filter کوي.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>یوازې هغه files ورکوي چې دا tags ولري.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>هغه files exclude کوي چې دا tags ولري.</td></tr></tbody></table><h2 id="return-formats" tabindex="-1">Return Formats <a class="header-anchor" href="#return-formats" aria-label="Permalink to &quot;Return Formats&quot;">​</a></h2><p>له <code>type</code> پرته، API مستقیم random file URL ته redirect کوي.</p><p>له <code>type=url</code> سره، text URL ورکوي.</p><p>له <code>type=json</code> سره، file information ورکوي، پکې file URL، file ID، file name، file type، tags، rating او related metadata شامل دي.</p><h2 id="access-rules" tabindex="-1">Access Rules <a class="header-anchor" href="#access-rules" aria-label="Permalink to &quot;Access Rules&quot;">​</a></h2><p>Random Image API د public access rules تعقیبوي:</p><table tabindex="0"><thead><tr><th>Rule</th><th>اغېز</th></tr></thead><tbody><tr><td>Directory restriction</td><td>یوازې په allowed directories کې files ټاکل کېدای شي.</td></tr><tr><td>Blocklist</td><td>blocklisted files له random pool څخه exclude کېږي.</td></tr><tr><td>Allowlist mode</td><td>کله چې enabled وي، یوازې هغه files راګرځي چې public access ته allowed وي.</td></tr><tr><td>Age rating</td><td>R12، R16، R18 او ورته content د اوسني access mode له مخې filter کېږي.</td></tr></tbody></table><p>که له filtering وروسته هېڅ file match نه شي، API no matching result ورکوي.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API د speed ښه کولو لپاره directory candidate pools cache کوي.</p><p>له file changes وروسته، ImgBed د directory cache version update کوي، او وروسته requests candidate pool بیا جوړوي. Empty directories لنډ وخت cache کېږي، څو repeated queries کمې شي.</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery د هغو directories لپاره read-only public browsing page ورکوي چې visitors ته یې اجازه ورکوئ.</p><p>له فعالېدو وروسته visitors دا پرانیستلای شي:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-settings" tabindex="-1">Public Gallery Settings <a class="header-anchor" href="#public-gallery-settings" aria-label="Permalink to &quot;Public Gallery Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>موخه</th></tr></thead><tbody><tr><td>Enable</td><td>public gallery on یا off کوي. کله چې disabled وي، visitors یې browse نه شي کولای.</td></tr><tr><td>Image loading mode</td><td>کنټرولوي چې previews original images کاروي که thumbnails.</td></tr><tr><td>Open directories</td><td>ټاکي چې visitors کوم directories ته access لري.</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>موخه</th></tr></thead><tbody><tr><td>Original</td><td>visitor page original files مستقیم load کوي.</td></tr><tr><td>Thumbnail</td><td>visitor page د چټک loading لپاره thumbnails ته ترجیح ورکوي.</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories ټاکي چې visitors څه لیدلای شي.</p><p>د بېلګې په توګه:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>بیا visitors دا پرانیستلای شي:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirectories هم open کېدای شي، لکه <code>/2026/lucky/</code>. visitors له هغو directories څخه blocked وي چې open نه وي.</p><h2 id="public-gallery-features" tabindex="-1">Public Gallery Features <a class="header-anchor" href="#public-gallery-features" aria-label="Permalink to &quot;Public Gallery Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>تشریح</th></tr></thead><tbody><tr><td>Browse directories</td><td>په open directories کې files او subdirectories کتل.</td></tr><tr><td>Search</td><td>د file name، file ID یا tags له مخې search.</td></tr><tr><td>Type filter</td><td>images، videos، audio یا نور files filter کول.</td></tr><tr><td>Tag filter</td><td>ټاکلي tags include یا exclude کول.</td></tr><tr><td>Orientation filter</td><td>landscape یا portrait images filter کول.</td></tr><tr><td>Time filter</td><td>د upload time range له مخې filter کول.</td></tr><tr><td>Extension filter</td><td>د file extension له مخې filter کول.</td></tr><tr><td>Copy link</td><td>د file access links copy کول.</td></tr><tr><td>Media preview</td><td>د visitor page پر images، videos او audio کتل یا play کول.</td></tr></tbody></table><h2 id="public-gallery-access-rules" tabindex="-1">Public Gallery Access Rules <a class="header-anchor" href="#public-gallery-access-rules" aria-label="Permalink to &quot;Public Gallery Access Rules&quot;">​</a></h2><p>public gallery هم public access rules تعقیبوي:</p><table tabindex="0"><thead><tr><th>Rule</th><th>اغېز</th></tr></thead><tbody><tr><td>Open directories</td><td>یوازې allowed directories ښودل کېږي.</td></tr><tr><td>Access mode</td><td>content د اوسني age-rating access mode له مخې filter کېږي.</td></tr><tr><td>Allowlist mode</td><td>کله چې enabled وي، یوازې public access ته allowed files ښودل کېږي.</td></tr><tr><td>Blocklist</td><td>blocklisted files پټېږي.</td></tr></tbody></table>`,43)])])}const u=e(i,[["render",o]]);export{m as __pageData,u as default};
